import React, { useState, useEffect, useCallback } from "react";
import Fade from "@mui/material/Fade";
import Slide from "@mui/material/Slide";
import { Card } from "primereact/card";
import Environment from "Images/Environment.jpg";
import Community from "Images/Community.jpg";
import Economic from "Images/Economic.png";
import Health from "Images/Health.jpg";
import Personal from "Images/Personal.jpg";
import { Size } from "media-query";
import {
  cardbgcolor,
  textcolor,
  pagetitlecolor,
  cardtitlecolor,
  pagebgcolor,
  fontType,
} from "components/Display/feutures";

const topPageMax = 100;

const HDI_Context = [
  {
    title: "Environmental Security",
    context:
      "Environmental security focuses on safeguarding the natural environment to ensure a healthy, sustainable quality of life for current and future generations. It involves protecting ecosystems, ensuring access to clean air, water, and soil, and mitigating the impacts of climate change and pollution. By promoting sustainable practices, effective waste management, and conservation efforts, environmental security aims to prevent environmental degradation and enhance resilience against natural disasters. This holistic approach ensures that communities can thrive in a safe and stable environment, supporting both ecological balance and human well-being.",
    image: Environment,
    timeout: 2000,
  },
  {
    title: "Community Security",
    context:
      "Community security focuses on safeguarding the well-being and stability of neighborhoods by ensuring safety from crime, providing access to essential services, and promoting economic stability. It involves creating safe living conditions, fostering social cohesion, and protecting individuals' rights while addressing environmental and health concerns. Effective community security integrates crime prevention, emergency response, and community engagement, aiming to build resilient communities where residents can thrive without fear or threat, actively participate in local governance, and benefit from a supportive, inclusive environment.",
    image: Community,
    timeout: 2400,
  },
  {
    title: "Economic Security",
    context:
      "Economic security ensures that individuals and families have stable and sufficient income to meet their basic needs and achieve financial well-being. It involves creating and maintaining access to employment opportunities, affordable housing, and essential services, while also providing social safety nets such as unemployment benefits, pensions, and health insurance. By fostering economic stability through job creation, fair wages, and financial support systems, economic security aims to protect people from poverty and economic hardship, enabling them to maintain a decent standard of living and contribute to overall economic resilience.",
    image: Economic,
    timeout: 2800,
  },
  {
    title: "Health Security",
    context:
      "Health security focuses on ensuring that individuals and communities have access to essential healthcare services, including preventive care, treatment, and emergency medical support. It involves safeguarding against health threats such as diseases, pandemics, and environmental hazards by maintaining robust healthcare systems, effective disease surveillance, and emergency response capabilities. Health security also emphasizes the importance of access to affordable medicines, vaccines, and health education, aiming to protect and improve public health outcomes while reducing health disparities and enhancing resilience against health crises.",
    image: Health,
    timeout: 3200,
  },
  {
    title: "Personal Security",
    context:
      "Personal security involves safeguarding individuals from threats and harm, ensuring their safety and well-being in everyday life. It encompasses protection from physical violence, harassment, and abuse, as well as ensuring privacy and security in personal data and digital interactions. Personal security also includes access to reliable emergency services, legal protection, and support systems that address issues such as domestic violence and personal safety concerns. By fostering environments where individuals feel safe and protected, personal security allows people to live with confidence and peace of mind, contributing to overall quality of life and personal stability.",
    image: Personal,
    timeout: 3600,
  },
];

const Curtain = ({ imageIndex }) => (
  <div className="w-screen" style={{ backgroundColor: cardbgcolor }}>
    <Fade in timeout={1200}>
      <img
        className="flex mx-auto rounded-md p-2 w-80 h-44"
        src={HDI_Context[imageIndex].image}
        alt={HDI_Context[imageIndex].title}
      />
    </Fade>
  </div>
);

const WelcomeContext = ({ y }) => {
  const size = Size();
  const isSmallScreen = ["MD", "SM", "XS", "L"].includes(size);

  return (
    <div>
      <div
        className={
          isSmallScreen
            ? "grid grid-rows-2 gap-2 p-2"
            : "grid grid-cols-2 gap-2 p-2"
        }
      >
        {["right", "left"].map((direction, index) => (
          <Slide
            direction={direction}
            in={y < topPageMax}
            timeout={1300}
            key={index}
          >
            <p
              style={{
                backgroundColor: cardbgcolor,
                color: textcolor,
                fontFamily: fontType,
              }}
              className="bg-opacity-75 shadow-md rounded-md p-4"
            >
              {index === 0
                ? "In South Africa, the human development approach guides our work, focusing on real, meaningful freedom—not just legal rights, but the actual ability to make choices about our lives. This approach prioritizes improving well-being and expanding freedoms, placing people at the heart of the analysis. It examines how political, social, environmental, and economic factors shape the choices available to individuals. Pioneered by Dr. Mahbub ul Haq and Amartya Sen, this framework introduced the Human Development Index (HDI) to measure how well people can live long, healthy lives, access education, and maintain a decent standard of living. The HDI, first presented in the 1990 Human Development Report, shifted focus from economic size to the well-being of people, setting a global standard for tracking human progress."
                : "In the South African context, this means addressing inequalities and enhancing quality of life by ensuring all citizens have access to essential services and opportunities. It involves not only expanding choices but also protecting people from threats and ensuring their safety. The approach also emphasizes 'capabilities'—the real opportunities people have to live fulfilling lives. This includes good health, education, income, safety, and more. Some capabilities come from personal effort, while others depend on external conditions, such as access to quality education and public services. Capabilities can also be influenced by birth circumstances or legal rights. Human security, a key concept in this framework, focuses on protecting people from threats and ensuring their safety, rather than just state security. It addresses resilience and vulnerability, aiming to create an environment where everyone can make choices freely and safely. For example, improving human security in South Africa involves addressing issues like crime and inadequate public services, ensuring that all individuals can lead secure and fulfilling lives."}
            </p>
          </Slide>
        ))}
      </div>
    </div>
  );
};

const Welcome2 = ({ y }) => {
  const size = Size();
  const isSmallScreen = ["MD", "SM", "XS", "L"].includes(size);

  return (
    <div
      className={
        isSmallScreen ? "grid grid-rows-3 gap-1" : "grid grid-cols-3 gap-1"
      }
      style={{ backgroundColor: "transparent" }}
    >
      {HDI_Context.map(({ title, context, image, timeout }, index) => (
        <Card key={index} style={{ backgroundColor: cardbgcolor }}>
          <Fade in timeout={timeout}>
            <div>
              <h1
                style={{ color: cardtitlecolor, fontFamily: fontType }}
                className="flex text-center justify-center text-xl mb-1 font-bold"
              >
                {title}
              </h1>
              <p
                style={{ color: textcolor, fontFamily: fontType }}
                className="grid grid-flow-col gap-1 mb-1"
              >
                {context}
              </p>
              <img className="rounded-md" src={image} alt={title} />
            </div>
          </Fade>
        </Card>
      ))}
    </div>
  );
};

export const Solutions = () => {
  const [imageIndex, setImageIndex] = useState(0);
  const [y, setY] = useState(window.scrollY);

  useEffect(() => {
    const handleScroll = () => setY(window.scrollY);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  useEffect(() => {
    window.scrollTo({ top: 0, left: 0, behavior: "smooth" });
  }, []);

  useEffect(() => {
    const intervalId = setInterval(
      () => setImageIndex((prevIndex) => (prevIndex + 1) % HDI_Context.length),
      2500
    );
    return () => clearInterval(intervalId);
  }, []);

  return (
    <div className="block h-auto" style={{ backgroundColor: pagebgcolor }}>
      <Fade in={y < topPageMax} timeout={1000}>
        <h1
          style={{ color: pagetitlecolor, fontFamily: fontType }}
          className="text-center font-bold text-3xl mt-16"
        >
          Solutions
        </h1>
      </Fade>
    </div>
  );
};
